const _ = require("lodash");
const problemsData = require("../../data/problems.json");

/**
 * Normalize tags to lowercase trimmed strings
 * @param {string|string[]} tags
 * @returns {string[]}
 */
function normalizeTags(tags) {
  if (!tags) return [];
  if (typeof tags === "string") {
    tags = tags.split(",");
  }
  return tags
    .map(t => t.trim().toLowerCase())
    .filter(t => t.length > 0);
}

/**
 * Filter problems by difficulty
 * @param {Array} problems
 * @param {number} difficulty
 * @returns {Array}
 */
function filterByDifficulty(problems, difficulty) {
  if (!difficulty) return problems;
  return problems.filter(p => p.difficulty === difficulty);
}

/**
 * Filter problems by tags (case-insensitive, all tags must be present)
 * @param {Array} problems
 * @param {string|string[]} tags
 * @returns {Array}
 */
function filterByTags(problems, tags) {
  const normalizedTags = normalizeTags(tags);
  if (normalizedTags.length === 0) return problems;
  return problems.filter(p => {
    const problemTags = (p.tags || []).map(t => t.toLowerCase());
    return normalizedTags.every(t => problemTags.includes(t));
  });
}

